insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('c96c1d0f-5995-5c70-9b5d-23563566c5ae','00000000-0000-0000-0000-00000000b006','eaton','Eaton Park','project','Căn hộ hạng sang ~3,76 ha · Mai Chí Thọ, An Phú','[{"key":"Tên thương mại","value":"Eaton Park (tên pháp lý: Khu nhà ở Tâm Lực)"},{"key":"Vị trí","value":"Mặt tiền đại lộ Mai Chí Thọ, P. An Phú, TP. Thủ Đức (Q.2 cũ)"},{"key":"Quy mô","value":"~3,76 ha (pháp lý 37.699,2 m²; Gamuda công bố 9,1 acre)"},{"key":"Quy mô sản phẩm","value":"6 tháp (A1–A6) · 1.968 căn hộ + 12 penthouse + 51 shop đế + 21 shophouse"},{"key":"Số tầng","value":"29–39 tầng · mật độ xây dựng ~40%"},{"key":"Pháp nhân CĐT","value":"CTCP Bất động sản Tâm Lực"},{"key":"Nhà phát triển","value":"Gamuda Land (Gamuda Berhad, Malaysia)"},{"key":"Khởi công","value":"Động thổ 8/12/2023 · hầm A5/A6 từ 26/3/2024"},{"key":"Bàn giao","value":"A5/A6 dự kiến Q1–Q3/2027 · các tháp còn lại Q4/2027"}]'::jsonb,null,'Định danh dự án Câu chuyện đầu tư trong 3 dòng: quỹ đất hạng sang khan hiếm mặt tiền Mai Chí Thọ, do CĐT ngoại Gamuda phát triển, pháp lý hoàn chỉnh (đã có sổ đất + GPXD), tiến độ thực — đón đúng sóng hạ tầng nút giao An Phú & Metro 1 vào giai đoạn bàn giao 2027.',0),
  ('2e97a7a9-5745-54c9-9628-fef8b55d78c2','00000000-0000-0000-0000-00000000b006','tq-vitri','Vị trí Mai Chí Thọ','project','Đại lộ 10 làn · cách CBD 6,5km · kề Thủ Thiêm','[]'::jsonb,null,'Tọa độ & ranh giới Cổng chính mặt tiền đại lộ Mai Chí Thọ (lộ giới 70m, 10 làn xe). Phía Bắc giáp đường vào Khu liên hợp TDTT Rạch Chiếc; phía Đông & Nam giáp rạch Bà Dạt (tạo mặt nước nội khu). Cách CBD Quận 1 6,5 km. Kết nối • ~5 phút tới Thảo Điền & bán đảo Thủ Thiêm • ~10–15 phút tới Quận 1 qua hầm Thủ Thiêm • ~3 phút tới ga Metro Rạch Chiếc (tuyến số 1) • ~30 phút tới sân bay Long Thành (khi vận hành) Lân cận: Estella Heights, Imperia, Lexington (đối diện), và The Global City (Masterise). Đây là một trong số ít quỹ đất mới còn lại trên trục Mai Chí Thọ.',1),
  ('94882149-71af-5602-8a96-601d0ba8d358','00000000-0000-0000-0000-00000000b006','tq-quymo','Quy mô 3,76 ha','project','6 tháp · mật độ ~40% · cơ cấu sản phẩm','[{"key":"Diện tích đất","value":"~3,76 ha (pháp lý 37.699,2 m²)"},{"key":"Mật độ xây dựng","value":"~40% — thấp cho căn hộ hạng sang"},{"key":"Tổng tháp","value":"6 (A1–A6), 29–39 tầng"},{"key":"Căn hộ","value":"1.968 căn"},{"key":"Penthouse","value":"12 căn"},{"key":"Shop khối đế","value":"51 shop (tầng 1–2)"},{"key":"Shophouse","value":"21 căn mặt tiền"}]'::jsonb,null,'Theo công bố quốc tế của Gamuda (The Edge Malaysia, 12/12/2024): khu đất 9,1 acre với cơ cấu trên. Một số nguồn môi giới nêu "~2.052 sản phẩm" — con số gộp ước tính, cần đối chiếu bảng hàng.',2),
  ('b4f206fc-9f5c-5204-b6d1-86a8f9f74a7b','00000000-0000-0000-0000-00000000b006','tq-thietke','Thiết kế Biophilic','project','AG INGO Studio (Singapore) · EDGE green','[]'::jsonb,null,'Kiến trúc phong cách Biophilic (gắn kết con người – thiên nhiên), cảm hứng tháp cao tầng Singapore với góc bo cong mềm mại. Đơn vị thiết kế kiến trúc: AG INGO Design Studio (Singapore). Đặc điểm thiết kế bán được • 2 tháp Alpine & Forest đạt chứng nhận công trình xanh EDGE (IFC – World Bank). • Trần cao sàn-tới-sàn tới 3,5m; sảnh đôi cao 8,9m; kính Triple Low-E cách nhiệt. • 100% căn không "cửa đối cửa", mỗi căn chỉ 1 tường chung — riêng tư & phong thủy tốt.',3),
  ('92d97102-3803-5882-8626-d6335e8c0f28','00000000-0000-0000-0000-00000000b006','tq-tongthau','Tổng thầu & chất lượng','project','Unicons (Coteccons) · chuẩn GQUAS','[]'::jsonb,null,'Phần hầm/móng giai đoạn đầu do Unicons (thuộc Coteccons Group) và Fountech thi công. Một số nguồn nêu phần thân có sự tham gia của Coteccons và Hòa Bình — cần xác minh hợp đồng từng gói thầu. Áp dụng hệ tiêu chuẩn chất lượng GQUAS của Gamuda (chấm điểm hoàn thiện theo chuẩn quốc tế) — công cụ marketing về độ tin cậy bàn giao của CĐT ngoại.',4),
  ('25b66750-b7ab-5f59-b288-85bcf8c20a97','00000000-0000-0000-0000-00000000b006','tq-phankhu2','Cấu trúc 2 phân khu','project','PK1 (A1–A4) · PK2 (A5–A6)','[]'::jsonb,null,'Hai phân khu có hầm thông nhau trong từng cụm. Mở bán theo 3 giai đoạn: GĐ1 = A5/A6, GĐ2 = A1/A2, GĐ3 = A3/A4 (xem cụm Giá & Chính sách).',5),
  ('c696793c-7d00-5a64-83f2-20356a87a552','00000000-0000-0000-0000-00000000b006','tq-giaithuong','Giải thưởng','project','PropertyGuru 2024 · 6 hạng mục','[]'::jsonb,null,'Tại Vietnam Property Awards 2024 (PropertyGuru, trao 15/11/2024), Eaton Park đoạt 6 hạng mục: • Best Lifestyle Condo Development • Best Luxury Condo Development (HCMC) • Best Condo Architectural & Landscape Design • Best Waterfront Development • Best Pet-Friendly Development Gamuda Land nhận tổng 13 giải, gồm "Nhà phát triển của thập kỷ". Giải thưởng là điểm cộng thương hiệu khi tư vấn, dù không thay thế thẩm định pháp lý/giá.',6),
  ('c2c90197-303d-54e2-a44f-23c3751291d4','00000000-0000-0000-0000-00000000b006','cdt-gamuda','Gamuda Land','developer','Mảng BĐS của Gamuda Berhad (Malaysia)','[]'::jsonb,null,'Gamuda Land là mảng phát triển BĐS của Gamuda Berhad — tập đoàn kỹ thuật – hạ tầng – BĐS niêm yết Bursa Malaysia (thành lập 1976; mảng Land tiền thân lập 1995). Thế mạnh gốc là nhà thầu hạ tầng (metro, đường cao tốc) — lợi thế thi công khác biệt so với CĐT thuần BĐS. Quy mô tại Việt Nam Vào VN từ 2007. Theo Chủ tịch HĐTV Gamuda Land VN Angus Liew (10/2025): danh mục 8 dự án, tổng vốn 5 tỷ USD, dự kiến rót thêm 6 tỷ USD; Việt Nam đóng góp ~45% mục tiêu doanh số toàn cầu của tập đoàn.',7),
  ('09e9043e-08fe-5620-9a34-c6bea7214fea','00000000-0000-0000-0000-00000000b006','cdt-vietnam','Danh mục Gamuda tại VN','developer','Gamuda City · Celadon · Elysian · Artisan…','[]'::jsonb,null,'Chiến lược thâu tóm quỹ đất sạch + triển khai nhanh. Bề dày KĐT lớn (Gamuda City, Celadon) là minh chứng năng lực vận hành dài hạn; tuy nhiên Eaton Park là dự án hạng sang đầu tiên của Gamuda tại lõi khu Đông.',8),
  ('3a96eb57-93c3-5fa9-8d9d-c9c591e09d2f','00000000-0000-0000-0000-00000000b006','cdt-taichinh','Sức khỏe tài chính','developer','FY2025 doanh thu kỷ lục RM16,4 tỷ','[{"key":"Doanh thu FY2025","value":"RM16,4 tỷ (kỷ lục) · LN ròng đạt mốc RM1 tỷ lần đầu"},{"key":"Orderbook xây dựng","value":"~RM38 tỷ"},{"key":"Gamuda Land FY2025","value":"Doanh số RM4,1 tỷ"},{"key":"Q1 FY2026","value":"LN ròng tập đoàn +5% → RM215,13 triệu"},{"key":"Doanh số Land Q1","value":"RM846 triệu (+34% YoY), 54% từ nước ngoài"}]'::jsonb,null,'Tài chính tập đoàn mẹ lành mạnh và tăng trưởng — yếu tố giảm rủi ro "CĐT hụt vốn giữa chừng", điểm cộng lớn so với một số chủ đầu tư nội gặp khó dòng tiền giai đoạn 2022–2024.',9),
  ('8adbf405-8da2-53c9-ba3b-f612c6f7651e','00000000-0000-0000-0000-00000000b006','cdt-qtp','Chiến lược QTP','developer','Quick Turnaround · vòng đời 5 năm','[]'::jsonb,null,'Gamuda theo mô hình QTP (Quick Turnaround Project): mua quỹ đất sạch, triển khai – bán – bàn giao trong vòng đời ~5 năm, tối ưu IRR. Đến Q1 FY2025 đang chạy 12 QTP tại VN, Anh, Úc với doanh số ~RM6,9 tỷ.',10),
  ('4d0eda13-d193-57bd-a9fb-811c44debf1a','00000000-0000-0000-0000-00000000b006','cdt-banhang','Kết quả bán hàng','developer','Q1 FY2026: bán 95% · GDV RM3,3 tỷ','[]'::jsonb,null,'Theo công bố Gamuda Berhad (Q1 FY2026, kết thúc 31/10/2025): Eaton Park đã bán 95%, GDV RM3,3 tỷ. Cùng Elysian (bán hết, RM1 tỷ) và Springville (95%, RM300 triệu), 3 dự án VN đóng góp doanh số ~RM4,6 tỷ. Việt Nam được tập đoàn gọi là "thị trường ngôi sao".',11),
  ('859b544d-1139-5173-b8bb-bf9b379be15c','00000000-0000-0000-0000-00000000b006','pl-nguongoc','Nguồn gốc & thương vụ M&A','legal','Gamuda mua Tâm Lực 315,8 triệu USD (2023)','[{"key":"Bên bán","value":"3 cá nhân: Nguyễn Hồng Giang (50%), Nguyễn Văn Việt (46%), Đặng Thị Dung (4%)"},{"key":"Tỷ lệ mua","value":"100% cổ phần Tâm Lực"},{"key":"Giá trị","value":"315,8 triệu USD (~7.300 tỷ đồng)"},{"key":"Cơ cấu","value":"Đặt cọc 1.000 tỷ trước · trả nốt ~6.300 tỷ khi hoàn tất"},{"key":"Động thổ","value":"8/12/2023"}]'::jsonb,null,'Dự án tiền thân do Công ty Điền Phúc Thành (từng có tên thương mại The Riverdale), sau chuyển sang CTCP Bất động sản Tâm Lực (ĐKKD 0314020818, lập 20/9/2016). Thương vụ Gamuda mua lại (giữa 2023) Là một trong những thương vụ M&A bất động sản lớn nhất Việt Nam năm 2023. Tổng mức đầu tư phát triển dự kiến ~1,1 tỷ USD.',12),
  ('eb8b1f28-8043-5494-8746-b5fc7462d230','00000000-0000-0000-0000-00000000b006','pl-timeline','Mốc pháp lý 2021–2023','legal','Chủ trương → 1/500 → giao đất → GPXD','[]'::jsonb,null,'Điểm mạnh: chuỗi pháp lý hoàn chỉnh và liên tục, đất đã có sổ trước khi Gamuda triển khai — nền pháp lý chắc hiếm có ở phân khúc hạng sang khu Đông.',13),
  ('2f136c51-e926-5e10-a83a-19e5e66d3c5d','00000000-0000-0000-0000-00000000b006','pl-gpxd','GPXD & sổ đất','legal','07/GPXD (17/2/2023) · GCN QSDĐ (28/10/2022)','[{"key":"Giấy phép xây dựng","value":"Số 07/GPXD ngày 17/02/2023"},{"key":"GCN QSDĐ","value":"Ký 28/10/2022"},{"key":"Tổng mức đầu tư duyệt","value":"3.983 tỷ đồng (phát triển thương mại ~1,1 tỷ USD)"},{"key":"Điều kiện bán","value":"Đã đủ điều kiện ký HĐMB & chuyển nhượng"}]'::jsonb,null,null,14),
  ('8c895640-0015-5e21-8349-12e2beac5061','00000000-0000-0000-0000-00000000b006','pl-sohuu','Hình thức sở hữu','legal','Lâu dài (VN) · 50 năm (NN) · shophouse 2072','[{"key":"Căn hộ — người Việt","value":"Sở hữu lâu dài"},{"key":"Căn hộ — người nước ngoài","value":"50 năm (theo luật, room ngoại 30%/tháp)"},{"key":"Shophouse / khối đế","value":"Theo thời hạn đất — đến 12/01/2072"}]'::jsonb,null,'Căn hộ sở hữu lâu dài cho người Việt là lợi thế giữ giá dài hạn. Lưu ý phân biệt thời hạn shophouse (đất đến 2072) khi tư vấn khách mua khối thương mại để đầu tư.',15),
  ('95488639-0e61-5a6c-9011-9241a656c0a1','00000000-0000-0000-0000-00000000b006','pl-nganhang','Ngân hàng đồng hành','legal','6 ngân hàng · bảo lãnh & cho vay','[]'::jsonb,null,'6 ngân hàng tài trợ/cho vay người mua tại Eaton Park: • Vietcombank, BIDV, VietinBank (nhóm quốc doanh) • OCB (nội) • Hong Leong Bank, Public Bank (Malaysia — đồng hương Gamuda)',16),
  ('6ebd5e32-c847-5a9b-bad4-46883befada9','00000000-0000-0000-0000-00000000b006','pl-luuy','Lưu ý thẩm định','legal','Tin đồn môi giới cần xác minh · rủi ro ra sổ','[]'::jsonb,null,'Các tuyên bố CHƯA được CĐT/báo chí uy tín xác nhận • Thương hiệu khách sạn 5 sao (Hilton…) quản lý Cove/Lagoon — chỉ là thông tin môi giới; nguồn chính thức (VIR) chỉ nêu "dịch vụ quản gia 5 sao". • Giá GĐ3 185–220 triệu/m² — tin đồn môi giới; báo chí uy tín không công bố giá m² chính thức (mức 7.000 USD/m² là phân tích của CGS International). • Cam kết tăng giá "x2, x3", lợi suất 7–12%/năm — kỳ vọng tiếp thị, dự án chưa bàn giao nên chưa có lịch sử giá kiểm chứng. • Lễ cất nóc toàn tháp A5/A6 — chưa thấy trên báo chí uy tín đến đầu 2026 (chỉ có cất nóc khối đế/shophouse, nguồn môi giới). Rủi ro tiến độ ra sổ Một số nguồn nêu lo ngại "vài dự án Gamuda từng chậm ra sổ" — cần theo dõi thực tế khi nhận bàn giao; yêu cầu cam kết tiến độ cấp sổ trong HĐMB.',17),
  ('111389d4-2712-5eea-9020-598ec38e0918','00000000-0000-0000-0000-00000000b006','pl-checklist','Checklist trước cọc','legal','6 bước due diligence cho người mua','[]'::jsonb,null,'• 1. Bản gốc GPXD 07/GPXD + GCN QSDĐ (28/10/2022). • 2. Văn bản đủ điều kiện bán nhà ở hình thành trong tương lai cho đúng tháp định mua. • 3. Chứng thư bảo lãnh ngân hàng cho nghĩa vụ bàn giao, ghi đúng mã căn. • 4. Xác nhận căn đã giải chấp khỏi khoản vay dự án của CĐT. • 5. Đối chiếu tiến độ thanh toán với trần luật: ≤70% trước bàn giao, ≤95% trước khi cấp sổ. • 6. Đọc kỹ điều khoản phạt chậm bàn giao / chậm ra sổ và cơ chế thoát trong HĐMB.',18),
  ('a8ea5dd5-1625-54ca-9b7d-8896e3da678e','00000000-0000-0000-0000-00000000b006','pk-a5a6','A5 Grove & A6 Strait','masterplan','GĐ1 · đã lên tầng cao · bàn giao sớm nhất','[{"key":"Vai trò","value":"Phân khu 2 · mở bán Giai đoạn 1 (5/2024)"},{"key":"Quy mô","value":"673 căn · A5 ~39 tầng, A6 ~37 tầng"},{"key":"Tiến độ","value":"Khởi công hầm 26/3/2024 · cuối 2025 đã lên ~tầng 33"},{"key":"Bàn giao","value":"Dự kiến Q1–Q3/2027 (sớm nhất dự án)"}]'::jsonb,null,'Là 2 tháp vào ở sớm nhất — phù hợp khách cần nhận nhà nhanh hoặc muốn rút ngắn thời gian "chôn vốn" trước dòng tiền cho thuê. Giá GĐ1 thấp nhất trong 3 đợt (~125 triệu/m²) nên biên tăng giá thứ cấp đã tích lũy tốt nhất.',19),
  ('8b3508ca-ad1f-5899-a391-ec15c0f1c36e','00000000-0000-0000-0000-00000000b006','pk-a1a2','A1 Alpine & A2 Forest','masterplan','GĐ2 · đạt chứng nhận xanh EDGE','[{"key":"Vai trò","value":"Phân khu 1 · mở bán Giai đoạn 2 (cuối 2024)"},{"key":"Quy mô","value":"A1 ~36 tầng/~342 căn · A2 ~29 tầng/~280 căn"},{"key":"Điểm nhấn","value":"Cả 2 tháp đạt chứng nhận công trình xanh EDGE (IFC)"},{"key":"Tiến độ","value":"8/2025 đã lên ~tầng 17–18"},{"key":"Giá GĐ2","value":"~142 triệu/m² · 1PN từ ~8 tỷ"}]'::jsonb,null,'Tháp Alpine & Forest mang câu chuyện "xanh" mạnh nhất (EDGE) — điểm cộng với khách quan tâm vận hành tiết kiệm năng lượng & tiêu chuẩn quốc tế.',20),
  ('6766e063-2c00-5540-91e5-38a5ef57fe22','00000000-0000-0000-0000-00000000b006','pk-a3a4','A3 Cove & A4 Lagoon','masterplan','GĐ3 · "tinh hoa" cuối · view sông Rạch Chiếc','[{"key":"Vai trò","value":"Phân khu 1 · mở bán Giai đoạn 3 (10/2025)"},{"key":"Quy mô","value":"A3 ~37 tầng/~343 căn · A4 ~37 tầng/~342 căn"},{"key":"Vị trí","value":"2 tháp cuối, view sông/rạch Bà Dạt đẹp nhất"},{"key":"Ra mắt","value":"Nhà mẫu 16–17/8/2025 · \"Eaton Park Summit\" 26/8/2025"},{"key":"Giá GĐ3","value":"~7.000 USD/m² (CGS Intl) · hấp thụ ~90–95%"},{"key":"Tiến độ","value":"8/2025 mới ~tầng 5 → bàn giao muộn nhất (~Q4/2027)"}]'::jsonb,null,'Được CĐT định vị là "mảnh ghép tinh hoa" cuối cùng; vị trí & view đẹp nhất nên giá cao nhất 3 giai đoạn. Booking GĐ3 vượt >3 lần giỏ hàng (VIR, 31/10/2025).',21),
  ('57095f9f-9361-5745-9a03-541d052c76b7','00000000-0000-0000-0000-00000000b006','pk-loaicang','Loại căn hộ','masterplan','1–3PN · penthouse · tỷ trọng','[]'::jsonb,null,'Cơ cấu nghiêng mạnh về 2PN (~59%) — sản phẩm "xương sống" cho cả ở thật và cho thuê. 1PN (~31%) là sản phẩm thanh khoản cho thuê tốt nhất hướng chuyên gia.',22),
  ('aff29f7a-37a8-5452-93d0-3cd9ee8fb29f','00000000-0000-0000-0000-00000000b006','pk-shophouse','Shophouse & khối đế','masterplan','21 shophouse + 51 shop · phố thương mại','[{"key":"Shophouse mặt tiền","value":"21 căn · 85,6–176 m² (nhà phố TM)"},{"key":"Shop khối đế","value":"51 shop · 48,6–417,8 m² (tầng 1–2)"},{"key":"Sở hữu","value":"Theo thời hạn đất đến 12/01/2072"},{"key":"Giá thứ cấp","value":"~57–112 tỷ/căn (môi giới, T5/2026)"}]'::jsonb,null,'Khối thương mại khai thác dòng tiền từ ~2.000 căn hộ nội khu + cư dân khu vực An Phú. Rủi ro: lấp đầy thương mại cần thời gian sau bàn giao; giá trị lớn nên thanh khoản hẹp hơn căn hộ.',23),
  ('74f2d259-7198-5c67-a83e-2de2189d2eca','00000000-0000-0000-0000-00000000b006','pk-bangiao','Tiêu chuẩn bàn giao','masterplan','Full nội thất · Bosch, Grohe, Daikin','[]'::jsonb,null,'Bàn giao full nội thất liền tường cao cấp: • Bếp: Bosch / Franke / Smeg / Kuppersbusch · đá Quartz (Vicostone/Phú Tài) • Thiết bị vệ sinh: Grohe / Duravit / Geberit / Kohler / Hansgrohe • Điều hòa: âm trần Daikin / Toshiba / Mitsubishi • Khác: khóa Yale, điện Schneider, tủ Woodlands/An Cường; 3PN có bồn tắm nằm',24),
  ('21427b76-2fec-56b3-ba67-5b1f4eb1db68','00000000-0000-0000-0000-00000000b006','pk-tiendo','Tiến độ xây dựng','masterplan','Cập nhật theo tháp · bàn giao 2027','[]'::jsonb,null,null,25),
  ('a4df761f-dccf-597a-b7ee-95fa26b84cdd','00000000-0000-0000-0000-00000000b006','pk-thietkecan','Đặc điểm căn hộ','masterplan','Không cửa đối cửa · trần cao 3,5m','[]'::jsonb,null,'• ~9–10 căn/sàn, 5 thang máy + thang thoát hiểm. • 100% căn không "cửa đối cửa", mỗi căn chỉ 1 tường chung — riêng tư & hợp phong thủy. • Trần cao sàn-tới-sàn tới 3,5m; kính Triple Low-E; thang máy tốc độ 2,5–3 m/s. • Bảo mật Face ID / QR tại sảnh & hầm. Bố cục mật độ căn/sàn thấp và không cửa đối cửa là điểm bán định tính được khách Việt coi trọng (riêng tư, phong thủy) — khác biệt so với chung cư mật độ cao.',26),
  ('9a2007a9-2968-56e5-9c1c-f9a016897e98','00000000-0000-0000-0000-00000000b006','ti-onsen','Onsen & Ice-Sauna','amenity','Điểm nhấn lần đầu tại căn hộ TP.HCM','[]'::jsonb,null,'Điểm nhấn tiện ích "độc nhất": hồ khoáng nóng Onsen ngoài trời và phòng xông hơi tuyết (ice-sauna) — được quảng bá là lần đầu xuất hiện tại một dự án căn hộ TP.HCM.',27),
  ('b8cd6c12-992f-5e3b-a698-72c5dd5b4601','00000000-0000-0000-0000-00000000b006','ti-hoboi','Hệ hồ bơi','amenity','Vô cực · liên hoàn · jacuzzi · sky pool','[]'::jsonb,null,'Hệ hồ bơi đa tầng: hồ bơi vô cực, liên hoàn, jacuzzi, hồ trẻ em và hồ bơi tầng thượng (sky pool) với view sông & thành phố. Cảnh quan nước gắn rạch Bà Dạt tạo không gian xanh – nước đặc trưng Biophilic.',28),
  ('d2d5708d-6b8e-5927-9abc-cd2e4b02a55d','00000000-0000-0000-0000-00000000b006','ti-theduc','Thể dục thể thao','amenity','Gym · golf 3D · sân đa năng','[]'::jsonb,null,'Hệ thể chất: gym, yoga, phòng golf 3D, sân thể thao đa năng (bóng rổ, cầu lông, tennis). Đáp ứng nhu cầu vận động của tệp cư dân trẻ thu nhập cao — nhóm khách thuê tiềm năng.',29),
  ('64da4198-96af-57bc-9fca-36686c1f78ab','00000000-0000-0000-0000-00000000b006','ti-congvien','Công viên & ven sông','amenity','Đường chạy ~1km · pet park >300m²','[]'::jsonb,null,'Mảng xanh – mặt nước: công viên ven sông & rạch, đường chạy/đạp xe ~1km, vườn BBQ, vườn nhiệt đới, và công viên thú cưng >300 m² (đoạt giải Best Pet-Friendly Development 2024).',30),
  ('52c701b7-be83-5211-9188-82570373e42a','00000000-0000-0000-0000-00000000b006','ti-treem','Khu trẻ em & giáo dục','amenity','Legend Art · Marvel House','[]'::jsonb,null,'Khu nghệ thuật & giáo dục trẻ em hợp tác Legend Art và Marvel House; sân chơi trẻ em trong nhà/ngoài trời. Tiện ích hướng gia đình giúp giữ chân cư dân ở thật, nâng chất lượng cộng đồng & giá thuê dài hạn.',31),
  ('26069b0d-0561-5f0c-9490-9a92beeb222d','00000000-0000-0000-0000-00000000b006','ti-clubhouse','Clubhouse & coworking','amenity','Lounge · billiards · studio sáng tạo','[]'::jsonb,null,'Tiện ích lifestyle: clubhouse, Residence Lounge & Billiards / Cigar lounge, không gian coworking và studio sáng tạo nội dung — bắt trend làm việc linh hoạt & creator economy của tệp cư dân trẻ. Tổng cộng dự án có hơn 100 tiện ích.',32),
  ('4e310f54-5235-5669-90b8-a6abbd8c03a4','00000000-0000-0000-0000-00000000b006','ht-nutgiao','Nút giao An Phú','infra','3.408 tỷ · 3 tầng · cách ~450m','[]'::jsonb,null,'Nút giao khác mức 3 tầng An Phú (vốn 3.408 tỷ) cách Eaton Park ~450m — chất xúc tác hạ tầng quan trọng nhất với dự án. Theo Giám đốc Ban Giao thông TP.HCM Nguyễn Anh Minh: công trình "có thể giảm ùn tắc tới 80%" cửa ngõ phía Đông. N1.2 chờ bàn giao >22.000 m² mặt bằng đường Lương Định Của trong Q1/2026.',33),
  ('fa62f748-bf2d-58a7-ad7f-f15f4359430b','00000000-0000-0000-0000-00000000b006','ht-metro','Metro số 1','infra','Đã vận hành 12/2024 · ga Rạch Chiếc ~3 phút','[]'::jsonb,null,'Metro số 1 (Bến Thành – Suối Tiên) đã vận hành thương mại từ 12/2024. Ga Rạch Chiếc cách dự án ~3 phút di chuyển — kết nối nhanh về trung tâm & Thủ Đức.',34),
  ('d723fabc-2ca2-5fe2-9af2-039ae7c2315d','00000000-0000-0000-0000-00000000b006','ht-maichitho','Đại lộ Mai Chí Thọ','infra','70m · 10 làn · hầm Thủ Thiêm','[]'::jsonb,null,'Mặt tiền đại lộ Mai Chí Thọ (lộ giới 70m, 10 làn) — trục Đông–Tây huyết mạch nối hầm Thủ Thiêm vào Quận 1 (~10–15 phút) và đi cao tốc Long Thành về phía Đông. Đây là "địa chỉ" giao thông đắt giá: mặt tiền đại lộ chính + hiển thị thương hiệu.',35),
  ('f1a7b057-acf5-5602-b93e-c1d84fd4b83c','00000000-0000-0000-0000-00000000b006','ht-caotoc','Cao tốc & sân bay Long Thành','infra','Mở rộng 8 làn · sân bay vận hành 2026','[]'::jsonb,null,'Cao tốc TP.HCM – Long Thành – Dầu Giây đang mở rộng từ 4 → 8 làn (dự kiến hoàn thành cuối 2026). Sân bay Long Thành giai đoạn 1 dự kiến vận hành giữa/cuối 2026 — Eaton Park nằm trên trục kết nối trực tiếp về sân bay.',36),
  ('ce86ed50-737d-584e-917a-a289a6300452','00000000-0000-0000-0000-00000000b006','ht-vanhdai','Vành đai & cầu kết nối','infra','VĐ2/VĐ3 · Liên Phường · cầu Thủ Thiêm','[]'::jsonb,null,'Mạng lưới bổ trợ: Vành đai 2 (đang khép kín), Vành đai 3 (hoàn thành giữa 2026), đường Liên Phường, hệ thống cầu Thủ Thiêm — cùng tạo lưới giao thông đa hướng giảm phụ thuộc một trục, tăng giá trị kết nối vùng cho khu An Phú – Thủ Thiêm.',37),
  ('29cf5987-276c-5e8c-b0f2-b6a895d9301a','00000000-0000-0000-0000-00000000b006','ht-tacdong','"Điểm rơi" hạ tầng 2026–2027','infra','Hạ tầng hoàn thiện trùng giai đoạn bàn giao','[]'::jsonb,null,'Luận điểm thời điểm: người mua hiện vào trước khi cụm hạ tầng hoàn thiện; bàn giao 2027 rơi sau khi nút giao & sân bay vận hành — cấu trúc thời gian thuận cho tăng giá, với điều kiện các mốc không trượt dài.',38),
  ('05c6ae5b-664e-58cd-9682-75dab341f02a','00000000-0000-0000-0000-00000000b006','cs-lotrinhgia','Lộ trình giá sơ cấp','policy','5.300 → 6.000 → 7.000 USD/m² (CGS Intl)','[]'::jsonb,null,'Theo khảo sát thực địa của CGS International (4–5/11/2025), giá sơ cấp tăng đều qua 3 đợt, GĐ cuối hấp thụ ~95%. Đây là nguồn phân tích độc lập đáng tin hơn con số đồn của môi giới.',39),
  ('dcdac58e-fc81-57bb-9c85-8211b9d6bdc5','00000000-0000-0000-0000-00000000b006','cs-gd1','Giá GĐ1 (A5/A6)','policy','1PN ~6–7 tỷ · 2PN ~8,6–9,4 tỷ','[{"key":"Đơn giá","value":"~125 triệu/m²"},{"key":"1PN","value":"~6,1–7 tỷ"},{"key":"2PN","value":"~8,6–9,4 tỷ"},{"key":"3PN","value":"từ ~13 tỷ"},{"key":"Hấp thụ","value":">90%"}]'::jsonb,null,'GĐ1 là mặt bằng giá thấp nhất — khách vào sớm đã tích lũy biên tăng giá tốt nhất. Hiện chủ yếu giao dịch thứ cấp/chuyển nhượng với 2 tháp này.',40),
  ('0da4faab-09cd-5936-8fd6-0029b7ab2fea','00000000-0000-0000-0000-00000000b006','cs-gd3','Mở bán GĐ3 (A3/A4)','policy','10/2025 · booking >3x giỏ hàng','[]'::jsonb,null,'Gamuda khởi động GĐ3 bằng sự kiện "Eaton Park Summit" (26/8/2025 tại GEM Center, >1.200 nhân sự/28 đại lý), ra mắt tháp Lagoon "mảnh ghép tinh hoa" cuối. Mở bán chính thức 10/2025: bán ~90% trong vài giờ, booking vượt >3 lần giỏ hàng (VIR 31/10/2025).',41),
  ('6f2200c0-e941-5162-aeb3-265d5a3da879','00000000-0000-0000-0000-00000000b006','cs-thucap','Giá thứ cấp (T5/2026)','policy','All-in qua môi giới — tham khảo','[]'::jsonb,null,null,42),
  ('835a79e9-c2d7-5600-b8b7-45ec31d6546e','00000000-0000-0000-0000-00000000b006','cs-thanhtoan','Chính sách thanh toán','policy','Giãn ~30% đến nhận nhà · vay 70–80%','[]'::jsonb,null,'Các phương án (dự kiến) Phí quản lý Căn hộ ~29.000đ/m²/tháng; shophouse ~35.000đ/m²/tháng.',43),
  ('5ae65420-9847-5904-acd8-d021a232a738','00000000-0000-0000-0000-00000000b006','cs-yield','Tỷ suất cho thuê','policy','Thực tế ~4–6%/năm · khan cung hỗ trợ','[]'::jsonb,null,'Nguồn môi giới nêu kỳ vọng cho thuê khu Quận 2 ~4–6%/năm (một số nêu 7–12% — thiếu cơ sở, không nên dùng) và tăng giá ~8–12%/năm. Bối cảnh cung – cầu hỗ trợ Theo dữ liệu Savills (chia sẻ tại khảo sát CGS, 11/2025): TP.HCM chỉ có ~9.000 căn hộ mở bán mới trong 9 tháng đầu 2025 — thấp hơn nhiều so với nhu cầu ước tính ~50.000 căn/năm. Khan cung là lực đỡ giá trung hạn.',44),
  ('69c08292-ccfa-5b8a-9a65-1bcc82cfd92e','00000000-0000-0000-0000-00000000b006','tt-bicanh','Bối cảnh thị trường HCM','comparable','CBRE/Savills 2025 · cao cấp dẫn dắt · khan cung','[]'::jsonb,null,'• Giá sơ cấp căn hộ TP.HCM tăng ~8% so 2024 (Savills Q3/2025); thứ cấp khu Đông tăng mạnh (Thủ Thiêm/Nam Rạch Chiếc 18–27%/năm; Thảo Điền/An Phú 13–19%/năm — Dat Xanh Services). • Khan cung mới: ~9.000 căn mở bán 9T/2025 so với nhu cầu ~50.000 căn/năm (Savills). • Phân khúc cao cấp/hạng sang dẫn dắt nguồn cung & hấp thụ (~91% nhóm cao cấp). Kết luận khung: Eaton Park bán đúng vùng giá cao cấp trong thị trường khan cung — lực đỡ tốt, nhưng mặt bằng giá chung đã cao nên biên an toàn mỏng hơn chu kỳ trước.',45),
  ('9bee9cee-1ec1-5a45-b741-e89f2ab2bdde','00000000-0000-0000-0000-00000000b006','tt-globalcity','vs The Global City','comparable','Đối trọng trực tiếp · Masterise 117ha','[{"key":"Quy mô","value":"TGC 117 ha (đại đô thị) vs Eaton 3,76 ha (boutique hạng sang)"},{"key":"Giá căn hộ","value":"TGC ~120–150 tr/m² vs Eaton ~125–165 tr/m²"},{"key":"Vị trí","value":"Cùng An Phú; TGC sâu hơn (Đỗ Xuân Hợp), Eaton mặt tiền Mai Chí Thọ kề Thủ Thiêm"}]'::jsonb,null,'Đối đầu khi khách phân vân • TGC thắng: hệ tiện ích đại đô thị tự chủ (mall 123.000m², kênh nhạc nước, trường quốc tế), "downtown mới". • Eaton thắng: quy mô nhỏ riêng tư, mặt tiền đại lộ chính + gần Thủ Thiêm/metro hơn, CĐT ngoại, bàn giao full nội thất, pháp lý gọn.',46),
  ('6cc5a529-9858-5fa7-a3b1-8bd0d8cf61ed','00000000-0000-0000-0000-00000000b006','tt-thuthiem','vs Thủ Thiêm hạng sang','comparable','Empire · Metropole · cao hơn Eaton','[]'::jsonb,null,'Thủ Thiêm là "trần giá" khu Đông, cao hơn Eaton Park đáng kể. Khoảng cách giá Eaton (125–165) ↔ Thủ Thiêm (180–400) tạo dư địa kể chuyện: Eaton là hạng sang "cận lõi" với giá vào hợp lý hơn, hưởng spillover khi Thủ Thiêm hoàn thiện.',47),
  ('9ab81e88-e2d0-5153-98cb-4075f940efb6','00000000-0000-0000-0000-00000000b006','tt-cu','vs Dự án cũ Thảo Điền/An Phú','comparable','Masteri Thảo Điền · Estella · Vista','[]'::jsonb,null,'Dự án cũ rẻ hơn nhưng đã qua sử dụng, thiết kế/tiện ích lỗi thời và không còn nguồn cung mới mặt tiền Mai Chí Thọ. Eaton Park là hàng sơ cấp hạng sang đầu tiên tại An Phú sau nhiều năm — premium giá phản ánh tính mới + khan hiếm.',48),
  ('236745c1-05c9-5361-8698-266516489972','00000000-0000-0000-0000-00000000b006','tt-dinhvi','Định vị & SWOT','comparable','Lợi thế / điểm yếu Eaton Park','[]'::jsonb,null,'Lợi thế (Strengths) • Quỹ đất hiếm mặt tiền Mai Chí Thọ, kề Thủ Thiêm & gần metro • CĐT ngoại Gamuda, tài chính mạnh, pháp lý hoàn chỉnh • Tiện ích vượt trội (Onsen, ice-sauna, 100+ tiện ích), bàn giao full nội thất • Thương hiệu xanh EDGE + giải PropertyGuru Điểm yếu / Thách thức (Weaknesses) • Thương hiệu Gamuda ở phân khúc hạng sang còn mới với khách VN (KĐT Celadon/Gamuda City là trung cấp) • Khu vực chưa có cộng đồng cư dân & tiện ích ngoại khu hiện hữu (khác Thảo Điền) • Giá vào đã cao → dư địa lướt sóng hẹp; mô hình QTP bán nhanh – thoát nhanh',49),
  ('c51050f2-a2c9-512a-b328-641534c4b5e1','00000000-0000-0000-0000-00000000b006','tt-thanhkhoan','Thanh khoản & tăng giá','comparable','Căn nhỏ thoát nhanh · biên lướt hẹp dần','[]'::jsonb,null,'Quy luật thanh khoản nội khu: • 1PN/2PN (6–12 tỷ): tệp mua & thuê lớn nhất, thanh khoản tốt nhất. • 3PN/penthouse (15–25 tỷ+): tệp hẹp hơn, thiên về tích sản/ở thật. • Shophouse (57–112 tỷ): siêu hẹp — tài sản giữ, phụ thuộc lấp đầy thương mại. Thứ cấp đã ghi nhận tăng so GĐ1, nhưng càng vào sau (GĐ3, thứ cấp) biên lợi nhuận lướt càng mỏng. Nhà đầu tư cần thanh khoản nên chọn 1–2PN vị trí/view khác biệt.',50),
  ('801413d7-358a-5b4f-bf91-0116346cadc5','00000000-0000-0000-0000-00000000b006','dt-thesis','Luận điểm đầu tư','finance','5 trụ cột của investment thesis','[]'::jsonb,null,'1 · Quỹ đất hạng sang khan hiếm Mặt tiền Mai Chí Thọ, không còn dự án mới cùng trục; hàng sơ cấp hạng sang đầu tiên tại An Phú sau nhiều năm. 2 · Pháp lý hoàn chỉnh Đã có GCN QSDĐ (10/2022) + GPXD (2/2023) — giảm rủi ro pháp lý so với nhiều dự án khu Đông. 3 · Sóng hạ tầng đúng nhịp Nút giao An Phú, Metro 1, sân bay Long Thành, mở rộng cao tốc hội tụ quanh giai đoạn bàn giao 2027. 4 · CĐT ngoại tài chính mạnh Gamuda FY2025 doanh thu kỷ lục RM16,4 tỷ — giảm rủi ro hụt vốn/treo dự án. 5 · Khan cung + đòn bẩy vốn thấp TP.HCM thiếu cung (9.000 vs 50.000 căn/năm); chính sách giãn ~30% đến nhận nhà.',51),
  ('e6ef6de0-422e-5b96-a8da-8b3ad9a67c20','00000000-0000-0000-0000-00000000b006','dt-dongtien','Dòng tiền (mô phỏng)','finance','Vốn ~30% đến nhận nhà · dồn khi bàn giao','[]'::jsonb,null,'Ví dụ căn 2PN ~10,5 tỷ, phương án thanh toán giãn: Đặc điểm: vốn bỏ ra đến nhận nhà thấp (~30%) — phù hợp khách có dòng tiền tương lai hoặc kế hoạch bán trước bàn giao. Nếu dùng đòn bẩy, gánh nặng lãi dồn về sau ân hạn.',52),
  ('4bd7417b-5479-5b58-b0f0-48eb2bb7be5d','00000000-0000-0000-0000-00000000b006','dt-ruiro','Bản đồ rủi ro','finance','Pháp lý · tiến độ · thanh khoản · lãi suất · cung','[]'::jsonb,null,null,53),
  ('0a5b61a7-4812-578c-839b-305acb071b04','00000000-0000-0000-0000-00000000b006','dt-khuyennghi','Chọn theo mục tiêu','finance','Khung khuyến nghị hành động','[]'::jsonb,null,null,54),
  ('1b6c3fb3-f4b1-5abe-be4c-eed26097fc06','00000000-0000-0000-0000-00000000b006','dt-trigger','Tín hiệu Mua / Thận trọng','finance','Benchmark cập nhật quyết định','[]'::jsonb,null,'Tín hiệu MUA mạnh hơn • Nút giao An Phú hoàn tất đúng các mốc 2026 (hầm HC1-02 đã thông 2/2026) • Sân bay Long Thành GĐ1 vận hành giữa–cuối 2026 • Gamuda bàn giao A5/A6 đúng hạn 2027 & ra sổ suôn sẻ • Thị trường khan cung tiếp diễn (cung mới < 1/5 nhu cầu) Tín hiệu THẬN TRỌNG • Lãi suất vay tăng mạnh sau ưu đãi • Nguồn cung khu Đông bung nhanh (TGC, Thủ Thiêm) làm chững giá/giảm yield • Tiến độ bàn giao/ra sổ chậm so cam kết • Chính sách CK/HTLS bị rút ngắn ở các đợt sau',55),
  ('21d7adb6-3f18-55cf-b948-512fa0a0b230','00000000-0000-0000-0000-00000000b006','dt-kh','Chân dung khách mua','finance','Gia đình trẻ · chuyên gia · NĐT trung–dài hạn','[]'::jsonb,null,'Tệp khách Eaton Park: • Gia đình trẻ thu nhập cao mua để ở — coi trọng tiện ích wellness, pet-friendly, riêng tư. • Chuyên gia nước ngoài / Việt kiều — thuận với ngân hàng Malaysia, thương hiệu ngoại, gần Thảo Điền/Thủ Thiêm. • Nhà đầu tư trung–dài hạn ưu tiên pháp lý sạch & thương hiệu CĐT, kỳ vọng capital-gain theo sóng hạ tầng.',56);
